needles = ("acerxo", "ticket-please-back", "ticket-please-backside")

for db in paths:
    try:
        con = sqlite3.connect(str(db))
        cur = con.cursor()
        cur.execute("SELECT name FROM sqlite_master WHERE type='table'")
        tables = [r[0] for r in cur.fetchall()]
        for table in tables:
            try:
                cur.execute(f"PRAGMA table_info({table})")
                cols = [c[1] for c in cur.fetchall()]
                if not {"key", "value"}.issubset(set(cols)) and not {"key"}.issubset(set(cols)):
                    # try generic
                    pass
                if "key" in cols and "value" in cols:
                    cur.execute(f"SELECT key, value FROM {table}")
                    rows = cur.fetchall()
                else:
                    continue
            except Exception:
                continue
            for key, value in rows:
                s = value.decode("utf-8", errors="ignore") if isinstance(value, (bytes, bytearray)) else str(value)
                blob = f"{key}\n{s}".lower()
                if any(n in blob for n in needles):
                    print(f"DB {db}")
                    print(f"TABLE {table}")
                    print(f"KEY {key}")
                    print(f"VAL {s[:1000]}")
                    print("---")
        con.close()
    except Exception as e:
